// Extract and validate incoming payload
const body = $input.first().json.body || $input.first().json;

const muscles = body.sore_muscles || [];
const timestamp = body.timestamp || new Date().toISOString();
const userId = body.user_id || 'anonymous';

if (!muscles || muscles.length === 0) {
  throw new Error('No sore muscles provided in the request payload.');
}

// Build a structured prompt context
const muscleList = muscles.join(', ');

return [{
  json: {
    muscles,
    muscleList,
    userId,
    timestamp,
    prompt: `You are a professional sports physiotherapist and recovery coach. 
A user reports soreness in the following muscle groups: ${muscleList}.

Create a targeted recovery plan with:
1. 4-6 rehabilitation exercises (low intensity, recovery-focused)
2. 4-6 targeted stretches (static and dynamic)

For each exercise or stretch, provide:
- id: unique string (e.g., "ex_1", "st_1")
- name: clear exercise name
- sets: number of sets (for exercises only, null for stretches)
- reps: rep range as string (e.g., "12-15") or null
- duration: time string (e.g., "30s", "45s", "1 min")
- description: 1-2 sentence clear instruction
- muscle: which muscle group this targets
- intensity: "low" | "medium" | "rest"
- tips: one key form tip

Respond ONLY with valid JSON in this exact structure (no markdown, no explanation):
{
  "plan_title": "Recovery Plan for [muscle list]",
  "estimated_duration": "X mins",
  "exercises": [...],
  "stretches": [...],
  "recovery_tips": ["tip1", "tip2", "tip3"]
}`
  }
}];

// Parse the Groq response and format it for the frontend
const groqResponse = $input.first().json;
const inputData = $('Parse & Validate Input').first().json;

let planData;

try {
  const rawContent = groqResponse.choices[0].message.content;
  // Strip any accidental markdown code fences
  const cleaned = rawContent.replace(/```json/g, '').replace(/```/g, '').trim();
  planData = JSON.parse(cleaned);
} catch (parseError) {
  // Fallback: return a structured error that frontend can handle
  return [{
    json: {
      success: false,
      error: 'Failed to parse AI response',
      muscles: inputData.muscles,
      timestamp: inputData.timestamp
    }
  }];
}

// Ensure IDs exist on every item
const exercises = (planData.exercises || []).map((ex, i) => ({
  ...ex,
  id: ex.id || `ex_${i + 1}`,
  type: 'exercise'
}));

const stretches = (planData.stretches || []).map((st, i) => ({
  ...st,
  id: st.id || `st_${i + 1}`,
  type: 'stretch',
  sets: st.sets || null,
  reps: st.reps || null
}));

return [{
  json: {
    success: true,
    plan_title: planData.plan_title || `Recovery Plan for ${inputData.muscleList}`,
    estimated_duration: planData.estimated_duration || '20-30 mins',
    muscles: inputData.muscles,
    exercises,
    stretches,
    recovery_tips: planData.recovery_tips || [],
    generated_at: new Date().toISOString(),
    user_id: inputData.userId
  }
}];
